import React from "react";
import Search from "./Search";
import { useGetMeQuery } from "../../redux/api/userApi";
import { useSelector, useDispatch } from "react-redux";
import { useLazyLogoutQuery } from "../../redux/api/authApi";
import { useNavigate, Link } from "react-router-dom";
import { logout } from "../../redux/features/userSlice";

const Header = () => {
  const navigate = useNavigate();
  const dispatch = useDispatch();

  // Automatically loads logged-in user
  useGetMeQuery();

  const [logoutApi] = useLazyLogoutQuery();

  const { user, isAuthenticated } = useSelector(
    (state) => state.user
  );

  const logouthandler = async () => {
    try {
      await logoutApi().unwrap(); // Call backend logout
      dispatch(logout());         // Clear Redux
      navigate("/login");
    } catch (err) {
      console.log("Logout error:", err);
    }
  };

  return (
    <nav className="navbar row px-4 py-3 shadow-sm bg-dark">

      {/* Logo */}
      <div className="col-12 col-md-3">
        <Link to="/" className="navbar-brand text-white">
          ShopAll
        </Link>
      </div>

      {/* Search */}
      <div className="col-12 col-md-6 my-2 my-md-0">
        <Search />
      </div>

      {/* Auth Section */}
      <div className="col-12 col-md-3 d-flex justify-content-end align-items-center">

        {isAuthenticated ? (
          <div className="dropdown">
            <button
              className="btn btn-dark dropdown-toggle"
              type="button"
              data-bs-toggle="dropdown"
            >
              {user?.name}
            </button>

            <ul className="dropdown-menu">
              <li>
                <Link className="dropdown-item" to="/me/profile">
                  Profile
                </Link>
              </li>

              <li>
                <button
                  className="dropdown-item text-danger"
                  onClick={logouthandler}
                >
                  Logout
                </button>
              </li>
            </ul>
          </div>
        ) : (
          <Link to="/login" className="btn btn-outline-light">
            Login
          </Link>
        )}
      </div>
    </nav>
  );
};

export default Header;
